// ========== 注册验证函数 ==========
static int validate_register_inputs(const char *phone, const char *password, 
                                     const char *confirm, char *err_msg, int err_size)
{
    // 1. 验证电话号码
    if(!phone || strlen(phone) == 0) {
        snprintf(err_msg, err_size, "请输入电话号码");
        return -1;
    }
    if(!is_valid_phone(phone)) {
        snprintf(err_msg, err_size, "电话号码必须为11位数字");
        return -2;
    }
    
    // 2. 验证密码
    if(!password || strlen(password) == 0) {
        snprintf(err_msg, err_size, "请输入密码");
        return -3;
    }
    if(strlen(password) < 6) {
        snprintf(err_msg, err_size, "密码长度不能少于6位");
        return -4;
    }
    
    // 3. 验证确认密码
    if(!confirm || strlen(confirm) == 0) {
        snprintf(err_msg, err_size, "请再次输入密码");
        return -5;
    }
    if(strcmp(password, confirm) != 0) {
        snprintf(err_msg, err_size, "两次输入的密码不一致");
        return -6;
    }
    
    // 4. 检查账号是否已存在
    if(find_user_by_phone(phone) >= 0) {
        snprintf(err_msg, err_size, "该电话号码已注册");
        return -7;
    }
    
    return 0;  // 验证通过
}

