// 注册按钮事件
void ui_event_Button3(lv_event_t * e)
{
    if(lv_event_get_code(e) == LV_EVENT_CLICKED) {
        // 如果键盘可见，不允许注册
        if(keyboard_visible) {
            show_warning_message("请先关闭键盘", 1500);
            return;
        }
        
        const char *phone = lv_textarea_get_text(ui_TextArea5);
        const char *password = lv_textarea_get_text(ui_TextArea6);
        const char *confirm = lv_textarea_get_text(ui_TextArea7);
        
        char err_msg[128];
        int result = validate_register_inputs(phone, password, confirm, err_msg, sizeof(err_msg));
        
        if(result == 0) {
            // 验证通过，执行注册
            int add_result = add_user(phone, password);
            if(add_result == 0) {
                show_success_message("注册成功！", 1500);
                
                // 清空输入框
                lv_textarea_set_text(ui_TextArea5, "");
                lv_textarea_set_text(ui_TextArea6, "");
                lv_textarea_set_text(ui_TextArea7, "");
                
                // 延迟返回登录界面
                lv_timer_t * timer = lv_timer_create(delayed_return_to_login, 1500, NULL);
                lv_timer_set_repeat_count(timer, 1);
            } else {
                show_error_message("注册失败，请重试", 2000);
            }
        } else {
            // 显示错误信息
            show_error_message(err_msg, 2000);
        }
    }
}

